module mux8to1 (
    input [2:0] sel,
    input [7:0] in0,
    input [7:0] in1,
    input [7:0] in2,
    input [7:0] in3,
    input [7:0] in4,
    input [7:0] in5,
    input [7:0] in6,
    input [7:0] in7,
    output [7:0] out
);

    reg [7:0] invalid_mux_output;  // Multiplexer output register

    always @(*) begin
        case (sel)
            3'b000: invalid_mux_output = in0;
            3'b001: invalid_mux_output = in1;
            3'b010: invalid_mux_output = in2;
            3'b011: invalid_mux_output = in3;
            3'b100: invalid_mux_output = in4;
            3'b101: invalid_mux_output = in5;
            3'b110: invalid_mux_output = in6;
            3'b111: invalid_mux_output = in7;
            default: invalid_mux_output = 8'b00000000;  // Default case (should not occur)
        endcase
    end

    assign out = invalid_mux_output;

endmodule
